import math

def classical_factoring_complexity(bits: int) -> float:
    # N = 2^bits, so ln(N) = bits * ln(2)
    ln_N = bits * math.log(2)
    ln_ln_N = math.log(ln_N)

    # GNFS exponent
    exp_value = 1.9 * (ln_N ** (1/3)) * (ln_ln_N ** (2/3))

    # Return as log base 2
    return exp_value / math.log(2)

def quantum_factoring_complexity(bits: int) -> float:
    # Shor's: O(bits^3)
    ops = bits ** 3
    return math.log2(ops)

def speedup_factor(bits: int) -> float:
    classical = classical_factoring_complexity(bits)
    quantum = quantum_factoring_complexity(bits)
    return 2 ** (classical - quantum)

def years_to_factor_classical(bits: int, ops_per_second: float = 1e12) -> float:
    complexity_bits = classical_factoring_complexity(bits)
    operations = 2 ** complexity_bits
    seconds = operations / ops_per_second
    years = seconds / (365.25 * 24 * 60 * 60)
    return years

from math import gcd
import random

def find_period(a: int, N: int) -> int:
    val = 1
    for r in range(1, N):
        val = (val * a) % N
        if val == 1:
            return r
    return None

def factor_with_period(N: int, a: int, r: int) -> tuple:
    if r is None or r % 2 == 1:
        return None

    x = pow(a, r // 2, N)

    if x == N - 1:  # x ≡ -1 (mod N)
        return None

    p = gcd(x - 1, N)
    q = gcd(x + 1, N)

    if p > 1 and p < N:
        return (p, N // p)
    if q > 1 and q < N:
        return (q, N // q)

    return None

def shors_classical_simulation(N: int, max_attempts: int = 10) -> tuple:
    for _ in range(max_attempts):
        a = random.randint(2, N - 1)

        # Check if we got lucky
        g = gcd(a, N)
        if g > 1:
            return (g, N // g)

        # Find period
        r = find_period(a, N)

        # Try to extract factors
        result = factor_with_period(N, a, r)
        if result:
            return result

    return None
